function formatNumber(n)
    local suffixes = {"", "k", "M", "B", "T", "Qa", "Qi", "Sx", "Sp", "Oc", "No", "Dc", "Ud", "Dd", "Td", "Qad", "Qid", "Sxd", "Spd", "Ocd", "Nod", "Vg"}
    local index = 1
    while n >= 1000 and index < #suffixes do n = n / 1000 index = index + 1 end
    return string.format("%.2f%s", n, suffixes[index])
end

function updateList()
    if not ContentListFrame.Visible then return end
    for _, child in pairs(ContentList:GetChildren()) do if child:IsA("Frame") then child:Destroy() end end
    local folder = Workspace:FindFirstChild("ActiveBrainrots")
    if not folder then return end
    local items = {}
    for _, part in pairs(folder:GetChildren()) do
        local income = part:GetAttribute("Income") or 0
        if part.Name == "ServerHitbox" and income >= 1e15 then table.insert(items, {Part = part, Income = income}) end
    end
    table.sort(items, function(a, b) return a.Income > b.Income end)
    
    for i, data in ipairs(items) do
        local part, income = data.Part, data.Income
        local ItemFrame = Instance.new("Frame")
        ItemFrame.Size = UDim2.new(1, -15, 0, 80); ItemFrame.BackgroundColor3 = Color3.fromRGB(15, 20, 25); ItemFrame.Parent = ContentList; Instance.new("UICorner", ItemFrame)
        
        local ItemStroke = Instance.new("UIStroke", ItemFrame)
        ItemStroke.Color = Color3.fromRGB(0, 100, 150)
        ItemStroke.Thickness = 1.5

        local MainLabel = Instance.new("TextLabel")
        MainLabel.Size = UDim2.new(0.7, 0, 1, 0); MainLabel.Position = UDim2.new(0, 15, 0, 0); 
        MainLabel.Text = (part:GetAttribute("Name") or "SYS_OBJ") .. "\n<font color='#00FF96'>$" .. formatNumber(income) .. "</font>"; 
        MainLabel.RichText = true; MainLabel.TextColor3 = Color3.fromRGB(200, 220, 255); 
        MainLabel.BackgroundTransparency = 1; MainLabel.TextXAlignment = Enum.TextXAlignment.Left; 
        MainLabel.Font = Enum.Font.Jura; MainLabel.TextSize = 18; MainLabel.Parent = ItemFrame
        
        local TpBtn = Instance.new("TextButton")
        TpBtn.Size = UDim2.new(0, 80, 0, 50); TpBtn.Position = UDim2.new(1, -95, 0.5, -25); 
        TpBtn.Text = "TP"; TpBtn.BackgroundColor3 = Color3.fromRGB(5, 30, 40); 
        TpBtn.TextColor3 = Color3.fromRGB(0, 255, 200); TpBtn.Font = Enum.Font.Jura; 
        TpBtn.TextSize = 20; TpBtn.Parent = ItemFrame; Instance.new("UICorner", TpBtn)

        local TpStroke = Instance.new("UIStroke", TpBtn)
        TpStroke.Color = Color3.fromRGB(0, 255, 200)
        TpStroke.Thickness = 1.5
        
        -- Animation für TP Button
        addHoverAnimation(TpBtn, 1.1)

        TpBtn.MouseButton1Click:Connect(function() 
            if Player.Character and Player.Character:FindFirstChild("HumanoidRootPart") then 
                Player.Character.HumanoidRootPart.CFrame = part.CFrame + Vector3.new(0, 3, 0) 
            end 
        end)
    end
end
